        <div style={{display:'flex',gap:8,marginBottom:14}}>{(['fotos','roi','pdf']as const).map(t=><button key={t}className="btn"onClick={()=>setPropTab(t)}style={{padding:'5px 14px',background:propTab===t?`${T.accent}20`:'transparent',border:`1px solid ${propTab===t?T.accent:T.border}`,borderRadius:6,color:propTab===t?T.accent:T.textSoft,fontSize:9,fontWeight:700,textTransform:'uppercase',letterSpacing:1}}>{t==='fotos'?'📸 Fotos':t==='roi'?'📊 ROI':'📄 PDF'}</button>)}</div>
